const DeepLinkHandler = ({ children }) => {
  useEffect(() => {
    const handleInitialURL = async () => {
      try {
        const initialUrl = await Linking.getInitialURL();
        if (initialUrl) {
          console.log('App opened with URL:', initialUrl);
        }
      } catch (error) {
        console.error('Error getting initial URL:', error);
      }
    };

    handleInitialURL();

    const subscription = Linking.addEventListener('url', ({ url }) => {
      console.log('Deep link received:', url);
      handleDeepLink(url);
    });

    return () => {
      subscription.remove();
    };
  }, []);

  const handleDeepLink = (url) => {
    console.log('Handling deep link:', url);
  };

  return children;
};

const parseDeepLink = (url) => {
  if (!url) return null;

  try {
    const urlObj = new URL(url);
    const path = urlObj.pathname.replace(/^\//, '');
    const segments = path.split('/');
    const queryParams = {};
    
    urlObj.searchParams.forEach((value, key) => {
      queryParams[key] = value;
    });

    return {
      scheme: urlObj.protocol.replace(':', ''),
      host: urlObj.host,
      path: path,
      segments: segments,
      params: queryParams,
    };
  } catch (error) {
    console.error('Error parsing deep link:', error);
    return null;
  }
};

const navigateFromDeepLink = (navigation, url) => {
  const parsed = parseDeepLink(url);
  if (!parsed) return;

  const { segments, params } = parsed;

  if (segments[0] === 'profile' && segments[1]) {
    navigation.navigate('Profile', { id: segments[1], ...params });
  } else if (segments[0] === 'payment' && segments[1]) {
    navigation.navigate('Payment', { action: segments[1], ...params });
  } else if (segments[0] === 'product' && segments[1]) {
    navigation.navigate('Product', { productId: segments[1], ...params });
  } else if (segments[0] === 'campaign' && segments[1]) {
    navigation.navigate('Campaign', { campaignId: segments[1], ...params });
  } else if (segments[0] === 'settings') {
    navigation.navigate('Settings', params);
  } else if (segments[0] === 'notifications') {
    navigation.navigate('Notifications', params);
  } else {
    navigation.navigate('Home');
  }
};

const App = () => {
  const navigationRef = React.useRef();

  useEffect(() => {
    const handleUrl = ({ url }) => {
      if (navigationRef.current) {
        navigateFromDeepLink(navigationRef.current, url);
      }
    };

    const subscription = Linking.addEventListener('url', handleUrl);

    Linking.getInitialURL().then((url) => {
      if (url && navigationRef.current) {
        setTimeout(() => {
          navigateFromDeepLink(navigationRef.current, url);
        }, 100);
      }
    });

    return () => {
      subscription.remove();
    };
  }, []);

  return (
    <DeepLinkHandler>
      <NavigationContainer ref={navigationRef} linking={linking} fallback={<Text>Loading...</Text>}>
        <Stack.Navigator>
          <Stack.Screen name="Home" component={HomeScreen} />
          <Stack.Screen name="Profile" component={ProfileScreen} />
          <Stack.Screen name="Payment" component={PaymentScreen} />
          <Stack.Screen name="Settings" component={SettingsScreen} />
          <Stack.Screen name="Notifications" component={NotificationsScreen} />
          <Stack.Screen name="Product" component={ProductScreen} />
          <Stack.Screen name="Campaign" component={CampaignScreen} />
        </Stack.Navigator>
      </NavigationContainer>
    </DeepLinkHandler>
  );
};

export default App;

import { View, Text, TouchableOpacity } from 'react-native';

export const createDeepLink = (screen, params = {}) => {
  const baseUrl = 'myapp://';
  let path = '';

  switch (screen) {
    case 'Profile':
      path = `profile/${params.id || ''}`;
      break;
    case 'Payment':
      path = `payment/${params.action || ''}`;
      break;
    case 'Product':
      path = `product/${params.productId || ''}`;
      break;
    case 'Campaign':
      path = `campaign/${params.campaignId || ''}`;
      break;
    case 'Settings':
      path = 'settings';
      break;
    case 'Notifications':
      path = 'notifications';
      break;
    default:
      path = '';
  }

  const queryString = Object.keys(params)
    .filter(key => !['id', 'action', 'productId', 'campaignId'].includes(key))
    .map(key => `${key}=${encodeURIComponent(params[key])}`)
    .join('&');

  return `${baseUrl}${path}${queryString ? '?' + queryString : ''}`;
};

export const openDeepLink = async (url) => {
  try {
    const canOpen = await Linking.canOpenURL(url);
    if (canOpen) {
      await Linking.openURL(url);
    } else {
      Alert.alert('Error', 'Cannot open this URL');
    }
  } catch (error) {
    console.error('Error opening deep link:', error);
    Alert.alert('Error', 'Failed to open deep link');
  }
};